class Solution:
    def maxPathLength(self, coordinates, k):
        n = len(coordinates)
        order = sorted(range(n), key=lambda i: (coordinates[i][0], coordinates[i][1]))
        end = [1] * n
        for idx, i in enumerate(order):
            xi, yi = coordinates[i]
            for j in order[:idx]:
                xj, yj = coordinates[j]
                if xj < xi and yj < yi:
                    if end[j] + 1 > end[i]:
                        end[i] = end[j] + 1
        rev = list(reversed(order))
        start = [1] * n
        for idx, i in enumerate(rev):
            xi, yi = coordinates[i]
            for j in rev[:idx]:
                xj, yj = coordinates[j]
                if xj > xi and yj > yi:
                    if start[j] + 1 > start[i]:
                        start[i] = start[j] + 1
        return end[k] + start[k] - 1

