import bisect
class Solution:
    def maxPathLength(self, coordinates, k):
        xk, yk = coordinates[k]

        def longest_chain(pts):
            if not pts:
                return 0
            pts = sorted(pts, key=lambda p: (p[0], -p[1]))
            tails = []
            for _, y in pts:
                idx = bisect.bisect_left(tails, y)
                if idx == len(tails):
                    tails.append(y)
                else:
                    tails[idx] = y
            return len(tails)

        before = [(x, y) for x, y in coordinates if x < xk and y < yk]
        after = [(x, y) for x, y in coordinates if x > xk and y > yk]
        return longest_chain(before) + longest_chain(after) + 1

