var maxPathLength = function(coordinates, k) {
    const xk = coordinates[k][0], yk = coordinates[k][1];

    function longestChain(pts) {
        if (pts.length === 0) return 0;
        pts.sort((a, b) => a[0] - b[0] || b[1] - a[1]);
        const tails = [];
        for (const [, y] of pts) {
            let lo = 0, hi = tails.length;
            while (lo < hi) {
                const mid = (lo + hi) >> 1;
                if (tails[mid] < y) lo = mid + 1; else hi = mid;
            }
            if (lo === tails.length) tails.push(y); else tails[lo] = y;
        }
        return tails.length;
    }

    const before = [];
    const after = [];
    for (const [x, y] of coordinates) {
        if (x < xk && y < yk) before.push([x, y]);
        else if (x > xk && y > yk) after.push([x, y]);
    }
    return longestChain(before) + longestChain(after) + 1;
};
